{
  "examples": [
    {
      "code": "def add(a: int, b: int) -> int {
    return a + b;
}

with entry {
    result: int = add(4, 6);
    print(result);
}",
      "explanation": "This module defines a typed Jac function-style ability named `add` that accepts two `int` values and returns an `int`. The `with entry` block is the program entry point; it calls `add(4, 6)`, stores the result in a typed local variable, and prints `10`."
    ,
    "granularity": "module"
    },
    {
      "code": "with entry {
    count: int = 0;
    while count < 3 {
        print(count);
        count += 1;
    }
}",
      "explanation": "Line 1 opens the entry block that runs when the module starts. Line 2 declares `count` as an `int` initialized to `0`. Line 3 starts a `while` loop that continues while `count` is less than `3`. Line 4 prints the current value. Line 5 increments `count`, allowing the loop to eventually stop."
    ,
      "granularity": "line"
    },
    {
      "code": "def classify(score: int) -> str {
    if score >= 90 {
        return "excellent";
    }
    if score >= 70 {
        return "passing";
    }
    return "needs work";
}

with entry {
    print(classify(82));
}",
      "explanation": "The `classify` block uses Jac `if` statements with braces to return early based on the numeric score. Because the first matching branch returns immediately, a score of `82` skips the `excellent` branch, matches the `passing` branch, and the entry block prints `passing`."
    ,
      "granularity": "block"
    },
    {
      "code": "node City {
    has name: str;
}

with entry {
    root() ++> City(name="Paris");
    root() ++> City(name="Lyon");
}",
      "explanation": "This module declares a graph node type `City` with a required string field `name`. In the entry block, `root()` refers to the current graph root node, and `++>` creates outgoing graph connections from the root to two new `City` nodes."
    ,
      "granularity": "module"
    },
    {
      "code": "obj Score {
    has name: str;
    has points: int = 0;

    def add(delta: int) -> int {
        self.points += delta;
        return self.points;
    }
}

with entry {
    s: Score = Score(name="Ava");
    print(s.add(5));
}",
      "explanation": "The `Score` object has stored state through `has` declarations. Its `add` ability updates `self.points` by the supplied `delta` and returns the new total. The entry block constructs a `Score` value with `name` set and uses the default `points` value of `0` before adding `5`."
    ,
      "granularity": "block"
    },
    {
      "code": "def sum_values(values: list[int]) -> int {
    total: int = 0;
    for value in values {
        total += value;
    }
    return total;
}

with entry {
    print(sum_values([2, 4, 6]));
}",
      "explanation": "Line 1 declares `sum_values` with a `list[int]` parameter and an `int` return type. Line 2 initializes the accumulator. Lines 3 through 5 iterate over the list and add each item. Line 6 returns the final sum. The entry block calls the function with three integers and prints `12`."
    ,
      "granularity": "line"
    },
    {
      "code": "node Reading {
    has value: int;

    def above(limit: int) -> bool {
        return self.value > limit;
    }
}

with entry {
    r: Reading = Reading(value=72);
    print(r.above(70));
}",
      "explanation": "This snippet uses a `node` type with a typed data field and a method-like ability. `above` reads the node instance through `self`, compares its `value` to the `limit`, and returns a `bool`. The entry block creates a `Reading` node value and prints whether it is above `70`."
    ,
      "granularity": "module"
    },
    {
      "code": "def first_non_empty(a: str, b: str) -> str {
    if not a {
        return b;
    }
    return a;
}

with entry {
    print(first_non_empty("", "fallback"));
}",
      "explanation": "The condition `not a` uses Jac boolean negation to test whether the string `a` is falsy. When `a` is empty, the function returns `b`; otherwise it returns `a`. The entry block therefore prints `fallback`."
    ,
      "granularity": "block"
    },
    {
      "code": "walker Tally {
    has count: int = 0;
}",
      "explanation": "This defines a Jac `walker` named `Tally`. The walker carries its own state with the `has count: int = 0;` declaration. Even without traversal logic shown here, the declaration establishes a graph-walking type that can later be given entry abilities."
    ,
      "granularity": "module"
    },
    {
      "code": "def max_pair(left: int, right: int) -> int {
    if left > right {
        return left;
    } else {
        return right;
    }
}

with entry {
    print(max_pair(8, 3));
}",
      "explanation": "Line 1 declares a typed function. Lines 2 through 6 form an `if`/`else` block using Jac braces. If `left` is greater than `right`, the function returns `left`; otherwise it returns `right`. The entry block prints the larger value from the pair."
    ,
      "granularity": "line"
    },
    {
      "code": "with entry {
    values: list[int] = [1, 3, 5, 7];
    found: bool = False;
    for value in values {
        if value == 5 {
            found = True;
        }
    }
    print(found);
}",
      "explanation": "The entry block declares a typed integer list and a Boolean flag. The `for` loop examines each value, and the nested `if` sets `found` to `True` when the value `5` appears. After the loop, the block prints the final flag."
    ,
      "granularity": "block"
    },
    {
      "code": "edge Road {
    has miles: int;
}

node Stop {
    has name: str;
}",
      "explanation": "This module declares two graph element types. `Road` is an `edge` with an integer property `miles`, and `Stop` is a `node` with a string property `name`. These declarations can be used later to build typed graph structures."
    ,
      "granularity": "module"
    },
    {
      "code": "def repeat_word(word: str, times: int) -> str {
    out: str = "";
    i: int = 0;
    while i < times {
        out = out + word;
        i += 1;
    }
    return out;
}

with entry {
    print(repeat_word("ha", 3));
}",
      "explanation": "The `repeat_word` block builds a string by repeatedly appending `word` while `i` is less than `times`. The loop state is explicit: `i` starts at `0`, increases by `1` each iteration, and controls termination. The entry block prints `hahaha`."
    ,
      "granularity": "block"
    },
    {
      "code": "obj Counter {
    has value: int = 0;

    def next() -> int {
        self.value += 1;
        return self.value;
    }
}

with entry {
    c: Counter = Counter();
    print(c.next());
    print(c.next());
}",
      "explanation": "Line 1 starts an object declaration. Line 2 gives each `Counter` instance a mutable integer field. Lines 4 through 7 define an ability that increments and returns that field. The entry block constructs a `Counter` and calls `next` twice, so the printed values are `1` and `2`."
    ,
      "granularity": "line"
    },
    {
      "code": "node Task {
    has title: str;
    has done: bool = False;
}

walker TaskWalker {
    has seen: int = 0;
}",
      "explanation": "The module defines a graph-oriented model: `Task` is a node type with task data, and `TaskWalker` is a walker type that can carry traversal state in `seen`. The walker does not yet define traversal abilities, but its state is declared and typed."
    ,
      "granularity": "module"
    },
    {
      "code": "def all_positive(values: list[int]) -> bool {
    for value in values {
        if value <= 0 {
            return False;
        }
    }
    return True;
}

with entry {
    print(all_positive([3, 1, 9]));
}",
      "explanation": "The function scans a list using a Jac `for` loop. If any element is zero or negative, it immediately returns `False`. If the loop finishes without finding such an element, the final `return True;` reports that all values are positive."
    ,
      "granularity": "block"
    },
    {
      "code": "def clamp(value: int, low: int, high: int) -> int {
    if value < low {
        return low;
    }
    if value > high {
        return high;
    }
    return value;
}

with entry {
    print(clamp(15, 0, 10));
}",
      "explanation": "Line 1 declares a helper with three integer parameters. The first `if` handles values below the lower bound. The second `if` handles values above the upper bound. If neither condition matches, the original value is already within range and is returned."
    ,
      "granularity": "line"
    },
    {
      "code": "node User {
    has name: str;
    has active: bool = True;

    def deactivate() -> bool {
        self.active = False;
        return self.active;
    }
}",
      "explanation": "The `User` node stores a name and an activity flag. Its `deactivate` ability mutates the node instance by setting `self.active` to `False`, then returns the updated Boolean value. This is graph-node state, not a separate dictionary or record."
    ,
      "granularity": "block"
    },
    {
      "code": "with entry {
    total: int = 0;
    for n in [1, 2, 3, 4] {
        if n % 2 == 0 {
            total += n;
        }
    }
    print(total);
}",
      "explanation": "This entry block combines list iteration, modulo arithmetic, and conditional control flow. Only values where `n % 2 == 0` are added to `total`, so the block sums the even numbers `2` and `4` and prints `6`."
    ,
      "granularity": "module"
    },
    {
      "code": "def countdown(start: int) -> int {
    current: int = start;
    while current > 0 {
        current -= 1;
    }
    return current;
}

with entry {
    print(countdown(4));
}",
      "explanation": "Line 1 defines `countdown` with an integer input and output. Line 2 copies the starting value into a mutable local. Lines 3 through 5 decrement it until the loop condition is false. Line 6 returns the final value, which is `0` for a positive start."
    ,
      "granularity": "line"
    }
  ]
}
